SELECT CAST(
    ( (SELECT overall_rating FROM Player_Attributes pa_ari WHERE pa_ari.player_api_id = (SELECT player_api_id FROM Player WHERE player_name = 'Ariel Borysiuk')) 
      - (SELECT overall_rating FROM Player_Attributes pa_paul WHERE pa_paul.player_api_id = (SELECT player_api_id FROM Player WHERE player_name = 'Paulin Puel')) 
    ) * 100.0 
    / (SELECT overall_rating FROM Player_Attributes pa_paul WHERE pa_paul.player_api_id = (SELECT player_api_id FROM Player WHERE player_name = 'Paulin Puel'))
) AS percentage_higher;	----- bird -----	european_football_2
